                    <CodeBlockLanguagePrimitive language=lang_display />
                    {filename.map(|f| view! {
                        <CodeBlockFilenamePrimitive filename=f />
                    })}
                </div>
                {show_copy.then(|| view! {
                    <CopyButtonIsland text=code.clone() />
                })}
            </CodeBlockHeaderPrimitive>
            <pre data-rs-code-pre="" inner_html=pre_html />
        </CodeBlockPrimitive>
    }
}

