//! @canon-level: strict
//! @canon-owner: primitives-team
//! Sheet Primitive - HTML puro + ARIA

use leptos::prelude::*;
use crate::meta::VisibilityState;
use crate::infra::state_engine::visibility_attrs;

#[derive(Clone, Copy, PartialEq, Default, Debug)]
pub enum SheetSide {
    #[default]
    Right,
    Left,
    Top,
    Bottom,
}
impl SheetSide {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Right  => "right",
            Self::Left   => "left",
            Self::Top    => "top",
            Self::Bottom => "bottom",
        }
    }
}

fn sheet_uid() -> String {
    use std::sync::atomic::{AtomicU64, Ordering};
    static CTR: AtomicU64 = AtomicU64::new(0);
    let ctr = CTR.fetch_add(1, Ordering::SeqCst);
    format!("sh-{:016x}-{:08x}",
        std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .map(|d| d.as_nanos() as u64)
            .unwrap_or(ctr),
        ctr)
}

#[component]
pub fn SheetPrimitive(
    children: Children,
    #[prop(default = VisibilityState::Closed)] state: VisibilityState,
    #[prop(default = SheetSide::Right)] side: SheetSide,
    #[prop(into, default = String::new())] class: String,
) -> impl IntoView {
    let s = visibility_attrs(state);
    view! {
        <div
            data-rs-sheet=""
            data-rs-interaction="overlay"
            data-rs-uid=sheet_uid()
            data-rs-component="Sheet"
            data-rs-behavior="overlay"
            data-rs-state=s.data_rs_state
            data-rs-side=side.as_str()
            class=class
        >
            {children()}
        </div>
    }
}

#[component]
pub fn SheetTriggerPrimitive(
    children: Children,
    #[prop(default = VisibilityState::Closed)] state: VisibilityState,
