#[derive(serde::Serialize, serde::Deserialize, Debug, Clone, Copy, PartialEq, Default)]
pub enum ToastVariant {
    #[default]
    Default,
    Success,
    Warning,
    Error,
    Info,
}

impl ToastVariant {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Default => "default",
            Self::Success => "success",
            Self::Warning => "warning",
            Self::Error => "error",
            Self::Info => "info",
        }
    }
    pub fn aria_live(&self) -> &'static str {
        match self { Self::Error => "assertive", _ => "polite" }
    }
    pub fn role(&self) -> &'static str {
        match self { Self::Error => "alert", _ => "status" }
    }
}

#[derive(serde::Serialize, serde::Deserialize, Debug, Clone, Copy, PartialEq, Default)]
pub enum ToastLifecycle {
    #[default]
    Open,
    Closing,
    Closed,
}

impl ToastLifecycle {
    pub fn as_str(&self) -> &'static str {
        match self { Self::Open => "open", Self::Closing => "closing", Self::Closed => "closed" }
    }
}

#[derive(serde::Serialize, serde::Deserialize, Debug, Clone, Copy, PartialEq, Default)]
pub enum ToastPosition {
    #[default]
    TopRight,
    TopLeft,
    BottomRight,
    BottomLeft,
    TopCenter,
    BottomCenter,
}

impl ToastPosition {
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::TopRight => "top-right",
            Self::TopLeft => "top-left",
            Self::BottomRight => "bottom-right",
            Self::BottomLeft => "bottom-left",
            Self::TopCenter => "top-center",
            Self::BottomCenter => "bottom-center",
        }
    }
}

#[component]
pub fn ToastPrimitive(
    children: Children,
    #[prop(default = ToastVariant::Default)] variant: ToastVariant,
    #[prop(default = VisibilityState::Open)] state: VisibilityState,
    #[prop(default = ToastLifecycle::Open)] lifecycle: ToastLifecycle,
    #[prop(into, optional)] title_id: Option<String>,
    #[prop(into, optional)] description_id: Option<String>,
    #[prop(into, default = String::new())] class: String,
) -> impl IntoView {
    let s = visibility_attrs(state);
    view! {
        <div
            data-rs-toast=""
            data-rs-component="Toast"
            data-rs-behavior="notification"
            data-rs-variant=variant.as_str()
            data-rs-state=s.data_rs_state
            data-rs-lifecycle=lifecycle.as_str()
            role=variant.role()
            aria-live=variant.aria_live()
            aria-atomic="true"
            aria-labelledby=title_id
            aria-describedby=description_id
            hidden=s.hidden
            class=class
        >
            {children()}
        </div>
    }
}

